export const logout = (
    succeed: () => void,
    failed: (msg: string) => void
) => {
    const logoutPromise = axios.get(
        // `${process.env["REACT_APP_API"]}/logout`,
        appConstants.URL+'/logout',
        {
            withCredentials: true   // carry or set cookie
        }
    );
    logoutPromise
        .then(res => {
            res.data.success ? succeed() : failed(res.data.message)
        })
        .catch(err => fail(err.message));
    return {
        type: appConstants.LOGOUT,
        payload: logoutPromise
    };
};


