import constant from "../constants/constant";
import {Component} from "react";
import axios from "axios";

class OwnerPendingClassroomList extends Component<OwnerPendingClassroomListProps, any> {

    state = {
        list: [{
            hardware: "sample hardware info",
            hours_end: "2014-09-20 00:00:00",
            hours_start: "2013-09-20 00:00:00",
            idclassroom: 25,
            location: "loc22"
        }]
    }

    componentDidMount() {
        axios.get(constant.URL+'/classroom/showpendingbyownerid/' + this.props.fromOwner.iduser)
            .then(res => {
                const data = res.data;
                this.setState({list: data})
            })
    }


    render() {
        return <div className="m-3">
            <h2>Some Tutors are interested in teaching at these Classrooms : </h2>

            {
                this.state.list.map(element => {
                    return (
                        <div key ={element.idclassroom} className="border border-dark h-50 w-25 d-sm-inline-block m-1">
                            <h4>Classroom# {element.idclassroom}</h4>
                            <h3>Alias: {element.hardware}</h3>
                            <h6>location: {element.location}</h6>
                            <h6>{element.hours_start} ~ {element.hours_end}</h6>
                            {/*<button>*/}
                            {/*    approve*/}
                            {/*</button>*/}
                        </div>
                    )
                })
            }

        </div>
    }
}

export default OwnerPendingClassroomList;

interface OwnerPendingClassroomListProps {
    fromOwner: any;
}