import React, {SyntheticEvent, useEffect, useState} from 'react';
import css from './Login.module.scss'
import {useDispatch} from "react-redux";
import {login} from "../actions/auth.action";
import appConstants from "../constants/constant";
import {useHistory} from "react-router-dom";
import {useTranslation} from "react-i18next";
//

// a functional component, just return....
export const Login = () => {

    const {t} = useTranslation()
    const [user, setUser] = useState({
        username: '',
        password: '',
    });


    useEffect(() => {
        // console.log('Login useEffect dependency: user changed to: ' ,user);
        localStorage.setItem('localStorageKey_user', JSON.stringify(user));
    }, [user])


    //useDispatch from react-redux
    const dispatch = useDispatch();

    // always const or let inside a function
    const updateHandler = (event: SyntheticEvent) => {
        const ele = event.target as HTMLInputElement;
        setUser({...user, [ele.id]: ele.value});
    };

    const history = useHistory();
    const submitHandler = (event: SyntheticEvent) => {
        event.preventDefault(); // pervent refresh of the page
        console.log('login submit user:::', user);
        dispatch(login(
            user,
            () => {
                history.push(appConstants.dashboardRoute);
            },
            (msg: string) => {
                console.log(msg);
            }
        ));
    };

    return (
        <form
            className={css.Login}
            onSubmit={submitHandler} // same as use button to submit( onClick on button )
        >
            <h2>{t("Log_in")}</h2>
            <label htmlFor="username">{t('username')}:</label>
            <input
                onChange={updateHandler}
                value={user.username}
                className="form-control"
                type="text"
                name="username"
                id="username"/>
            <label htmlFor="password">{t('password')}:</label>
            <input
                onChange={updateHandler}
                value={user.password}
                className="form-control"
                type="password"
                name="password" id="password"/>
            <br/>
            <button
                className="btn btn-success">
                {t("Log_in")}
            </button>
        </form>
    );
};
