import appConstants from "../constants/constant";
import {AxiosResponse} from "axios";
import {UserModel} from "../models/user.model";

export const ownersReducer = (
    state: UserModel[] | null = null,
    action: ownersReducerAction
) => {

    switch (action.type) {
        case appConstants.GET_CLASSROOMS_BY_OWNER:
            // console.log('GET_CLASSROOMS_BY_OWNER', (action.payload as AxiosResponse).data);
            return (action.payload as AxiosResponse).data;

        default:
            // console.log('reducer case: default case');
            return state;
    }
};

interface ownersReducerAction {
    type: string;
    payload: AxiosResponse;
}