import React from 'react';
import ReactDOM from 'react-dom';
import './index.scss';
import {BrowserRouter, Redirect, Route, Switch} from "react-router-dom";

import 'bootstrap/dist/css/bootstrap.min.css';
import reportWebVitals from './reportWebVitals';

import appConstants from "./constants/constant";
import App from "./App";
import ShowAllUser from "./test_use/ShowAllUsers";
import Products from "./test_use/Products";

import {Provider} from "react-redux";
import {applyMiddleware, createStore} from 'redux';

import {Login} from "./login/Login";

import {rootReducer} from "./reducers/root.reducer";
import reduxPromise from 'redux-promise';
import {withGuard} from "./hocs/withGuard";
import RegisterUser from "./login/RegisterUser";
import Dashboard from "./dashboard/Dashboard";
import LandingPage from "./Home/Home";
import PersonalInfo from "./header/PersonalInfo";


const root = document.getElementById('root');
const h1 = document.createElement('h1');
const textNode = document.createTextNode('something is wrong');
h1.appendChild(textNode);
root?.appendChild(h1);

const createStoreWithMiddleware = applyMiddleware(reduxPromise)(createStore);

ReactDOM.render(
    <Provider store={createStoreWithMiddleware(rootReducer)}>
        <BrowserRouter>
            <App>
                <Switch>
                    <Route path={appConstants.showAllUserRoute} component={ShowAllUser}/>
                    <Route path={appConstants.personalInfoRoute} component={PersonalInfo}/>
                    <Route path={appConstants.dashboardRoute} component={Dashboard}/>

                    <Route path={appConstants.productsRoute} component={Products}/>
                    <Route path={appConstants.homeRoute} component={LandingPage}/>

                    <Route path={appConstants.loginRoute} component={Login}/>
                    <Route path={appConstants.registerUserRoute} component={RegisterUser}/>
                    <Redirect path="*" to={appConstants.homeRoute}></Redirect>


                </Switch>
            </App>
        </BrowserRouter>
    </Provider>
    ,
    root
);


// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
