import {Component, SyntheticEvent} from "react";
import axios from "axios";
import constant from "../constants/constant";

class TutorAvailabilityList extends Component<TutorAvailabilityListProps, any> {

    state = {
        list: [{
            idavailability: 0,
            availability_id: 'number',
            classroom_id: 0,
            idtutor: 0,
            subject: '',
            hours_start: '',
            hours_end: '',
            status: ''
        }]
    }

    componentDidMount() {
        axios.get(constant.URL + '/availability/showbyuserid/' + this.props.fromOwner.iduser)
            .then(res => {
                const data = res.data;
                this.setState({list: data})
            })
    }

    deleteHandler = (event: SyntheticEvent, availabilityId: number|undefined) => {
        console.log('deleting ', availabilityId)
        axios({
            method: "delete",
            url: constant.URL+'/availability/deleteAvailabilityById/'+ availabilityId,
            headers: { "Content-Type": "application/json" },
        })
            .then(function (response) {
                alert(response.data);
            })
            .catch(function (response) {
                console.log(response);
            });
    }

    render() {
        return <div className="m-3">
            <h2>My Posted Availabilities : </h2>
            {
                this.state.list.map(element => {
                    return (
                        <div key={element.idavailability}
                             className="border border-dark h-50 w-25 d-sm-inline-block m-1">

                            <h4>idavailability: {element.idavailability}</h4>
                            <h4>idclassroom: {element.classroom_id}</h4>
                            <h6>subject: {element.subject}</h6>
                            <h6>{element.hours_start} ~ {element.hours_end}</h6>
                            <h5>status: {element.status}</h5>


                            <button onClick={ event => this.deleteHandler(event, element?.idavailability)}>
                                withdraw(delete)
                            </button>

                        </div>
                    )
                })
            }
        </div>
    }
}

export default TutorAvailabilityList;

interface TutorAvailabilityListProps {
    fromOwner: any;
}