import React, {SyntheticEvent} from "react";
import {RouteComponentProps} from "react-router";
import {Field, Form, Formik} from "formik";
import {UserUserinfoModel} from "../models/userUserinfo.model";
import css from './RegisterUser.module.scss'

import * as Yup from 'yup';
import axios from "axios";
import constant from "../constants/constant";


const RegisterUserFormValidationSchema = Yup.object().shape({
    username: Yup.string()
        .required('username is required')
});


class RegisterUser extends React.Component<RegisterUserProps, any> {

    // used by formit
    h2Ref = React.createRef<HTMLHeadingElement>();

    handleSubmit = (formData: UserUserinfoModel) => {

        console.log('formData from Formit',formData);



        axios({
            method: "put",
            url: constant.URL+'/user/register',
            data: JSON.stringify(formData),
            headers: { "Content-Type": "application/json" },
        })
            .then(function (response) {
                //handle success
                console.log(response);
            })
            .catch(function (response) {
                //handle error
                console.log(response);
            });
    }

    render() {
        return <>
            <p>register as user</p>
            <Formik
                onSubmit={this.handleSubmit}
                validationSchema={RegisterUserFormValidationSchema}
                initialValues={
                    {
                        username: 'u',
                        password: 'p',
                        email: 'e',
                        phone_home: '1',
                        phone_work: '1',
                        profilecol: ''
                    }
                }>
                {
                    ({errors, isValid}) => (
                        <Form className={css.RegisterUser}>
                            <h2 ref={this.h2Ref}>
                                Introduce yourself
                            </h2>

                            <label htmlFor="name">Username: </label>
                            <Field type="text" name="username" id="username"/>

                            <label htmlFor="password">Password: </label>
                            <Field type="password" name="password" id="password"/>

                            <label htmlFor="email">Email: </label>
                            <Field type="text" name="email" id="email"/>

                            <p>_____________</p>

                            <label htmlFor="phone_home">Phone Home: </label>
                            <Field type="text" name="phone_home" id="phone_home"/>

                            <label htmlFor="phone_work">Phone Work: </label>
                            <Field type="text" name="phone_work" id="phone_work"/>

                            <br/>
                            <button
                                type="submit"
                                disabled={!isValid}  // need a flag to disable button
                                className="btn btn-dark"
                            >
                                Register! (you can add role(s) later)
                            </button>
                        </Form>
                    )
                }
            </Formik>

        </>;
    }
}

interface RegisterUserProps {


}


export default RegisterUser;