import appConstants from "../constants/constant";
import {checkLogin} from "../actions/auth.action";


export const authReducer = (state: { username: string } | null = null,
                            action: authReducerAction) => {
    switch (action.type) {

        case appConstants.LOGIN:
            console.log('auth.reducer case LOGIN action.payload.data:  ', action.payload);
            alert(action.payload.data.message)
            // return action.payload.data.success ? action.payload.data.user.username : null;

            return null;

        case appConstants.LOGOUT:
            console.log('logout action.payload.data: ',action.payload.data);
            // return action.payload.data.success ? action.payload.data.user.username : null;

            localStorage.removeItem('localStorageKey_user');

            alert(action.payload.data.message)
            return null;

        case appConstants.CHECK_LOGIN:
            console.log('auth.reducer case CHECK_LOGIN action.payload.data:  ', action.payload.data);
            console.log('auth.reducer case CHECK_LOGIN action.payload.data.user:  ', action.payload.data.user);


            localStorage.setItem('localStorageKey_user', JSON.stringify(action.payload.data.user));

            return action.payload.data.success ? action.payload.data.user : null;


            // return action.payload.data.success ? action.payload.data.user : null;
            // return action.payload.data.success ? {username:'customer3'} : null;


        default:
            // console.log('auth.reducer DEFAULT case')
            return state;
    }
};

interface authReducerAction {
    type: string;
    payload: any;   // should be AXiOMS response}
}

