import React from "react";
import Modal from "react-modal";
import TutorAddAvailability from "../modals/TutorAddAvailability";
import TutorAvailabilityList from "./TutorAvailabilityList";
import {useTranslation} from "react-i18next";

const customStyles = {
    content: {
        width: '80%',
        top: '50%',
        left: '50%',
        right: 'auto',
        bottom: 'auto',
        marginRight: '-50%',
        transform: 'translate(-50%, -50%)',
    },
};

Modal.setAppElement('#root');

const Tutor = (fromDashboard: any) => {

    const {t} = useTranslation();
    const [modalIsOpen, setIsOpen] = React.useState(false);

    function openModal() {
        setIsOpen(true);
    }

    function closeModal() {
        setIsOpen(false);
    }

    return <>
        <h1>{t('Tutor')} sub{t('Dashboard')}</h1>

        <button onClick={openModal} className="btn btn-success">{t('Add_a_Class_to_teach')}</button>

        <Modal
            isOpen={modalIsOpen}
            onRequestClose={closeModal}
            style={customStyles}
            contentLabel="Example Modal"
        >
            <button onClick={closeModal}>{t('close')}</button>

            <TutorAddAvailability></TutorAddAvailability>
        </Modal>

        {fromDashboard.fromDashboard?.iduser}


        <div className='border border-dark w-75 m-3'>
            <TutorAvailabilityList fromOwner={fromDashboard.fromDashboard}/>
        </div>



    </>
}


export default Tutor;
