import constant, {ReduxState} from "../constants/constant";
import {Component, SyntheticEvent} from "react";
import {connect} from "react-redux";
import axios, {AxiosResponse} from "axios";
import {ClassroomModel} from "../models/Classroom.model";
import {getAllClassrooms} from "../actions/owners.action";

class OwnerClassroomList extends Component<OwnerClassroomListProps, any> {



    componentDidMount() {
        this.props.getAllClassrooms(this.props.fromOwner?.iduser);
    }

    deleteHandler = (event: SyntheticEvent, classroomId: number|undefined) => {
        console.log('delteing ', classroomId)
        axios({
            method: "delete",
            url: constant.URL+'/classroom/deleteClassroomById/'+ classroomId,
            headers: { "Content-Type": "application/json" },
        })
            .then(function (response) {
                console.log(response);
            })
            .catch(function (response) {
                console.log(response);
            });
    }


    render() {

        return <div className="m-3">
            <h2>My Classrooms : </h2>


            {
                this.props.classroomsList?.map(element => {
                    return (
                        <div key={element.idclassroom} className="border border-dark h-50 w-25 d-sm-inline-block m-1">
                            <h4>Classroom# {element.idclassroom}</h4>
                            <h3>Alias: {element.hardware}</h3>
                            <h6>location: {element.location}</h6>
                            <h6>{element.hours_start} ~ {element.hours_end}</h6>
                            <button>
                                edit
                            </button>
                            <button onClick={ event => this.deleteHandler(event, element?.idclassroom)}>
                                delete
                            </button>
                        </div>
                    )
                })
            }


        </div>
    }
}


function mapStateToProps1({classroomsList}: ReduxState) {
    return {classroomsList};
}

export default connect(mapStateToProps1, {getAllClassrooms})(OwnerClassroomList);

interface OwnerClassroomListProps {
    fromOwner: any;
    classroomsList: ClassroomModel[];
    getAllClassrooms: (idowner: number) => {
        type: string,
        payload: Promise<AxiosResponse>
    }

}