import React from "react";
import OwnerClassroomList from "./OwnerClassroomList";
import Modal from "react-modal";
import OwnerAddClassroom from "../modals/OwnerAddClassroom";
import OwnerPendingClassroomList from "./OwnerPendingClassroomList";
import {useTranslation} from "react-i18next";

const customStyles = {
    content: {
        top: '50%',
        left: '50%',
        right: 'auto',
        bottom: 'auto',
        marginRight: '-50%',
        transform: 'translate(-50%, -50%)',
    },
};

Modal.setAppElement('#root');

const Owner = (fromDashboard: any) => {

    const {t} = useTranslation();
    const [modalIsOpen, setIsOpen] = React.useState(false);

    function openModal() {
        setIsOpen(true);
    }

    function closeModal() {
        setIsOpen(false);
    }

    return <>
        <h1>{t('Owner')} {t('Dashboard')}</h1>

        <button onClick={openModal} className="btn btn-success">{t('Register_a_Classroom')}</button>

        <Modal
            isOpen={modalIsOpen}
            onRequestClose={closeModal}
            style={customStyles}
            contentLabel="Example Modal"
        >
            <button onClick={closeModal}>close</button>

            <OwnerAddClassroom></OwnerAddClassroom>
        </Modal>

        {fromDashboard.fromDashboard?.iduser}

        <div className='border border-dark w-75 m-3'>
            <OwnerClassroomList fromOwner={fromDashboard.fromDashboard}/>
        </div>

        <div className='border border-dark w-75 m-3'>
            <OwnerPendingClassroomList fromOwner={fromDashboard.fromDashboard}/>
        </div>

    </>
}


export default Owner;
