import React, {useEffect} from "react";
import Owner from "./Owner";
import Tutor from "./Tutor";
import {useTranslation} from "react-i18next";

const Dashboard = () => {

    const {t} = useTranslation();

    const data = window.localStorage.getItem('localStorageKey_user');
    const user = (data != 'undefined' && data) ? JSON.parse(data)
        :
        {username: 'if you see this , something is wrong', iduser: 0};

    return <>

        {t('Hello')},
        <br/>
        {t('username')}: {user?.username}
        <br/>
        {t('userid')}: {user?.iduser}
        <br/>

        <h1>{t('Dashboard')}</h1>

        <div className='border border-dark w-75 m-3'>
            <Owner fromDashboard={user}></Owner>
        </div>

        <div className='border border-dark w-75 m-3'>
            <Tutor  fromDashboard={user}></Tutor>
        </div>

    </>
}

export default Dashboard;


