import React, {SyntheticEvent} from "react";
import {Field, Form, Formik} from "formik";
import css from './OwnerAddClassroom.module.scss'

import * as Yup from 'yup';
import axios from "axios";
import {ClassroomModel} from "../models/Classroom.model";
import {useSelector} from "react-redux";
import constant, {ReduxState} from "../constants/constant";
import {useTranslation} from "react-i18next";


const OwnerAddClassroomFormValidationSchema = Yup.object().shape({
    // username: Yup.string()
    //     .required('username is required')
});


const OwnerAddClassroom = () => {

    const {t} = useTranslation();
    const h2Ref = React.createRef<HTMLHeadingElement>();

    const  handleSubmit  = (formData: ClassroomModel) => {

        console.log('formData from Formit', formData);

        axios({
            method: "put",
            url: constant.URL+'/classroom/add',
            data: JSON.stringify(formData),
            headers: {"Content-Type": "application/json"},
        })
            .then(function (response) {
                console.log(response);
            })
            .catch(function (response) {
                console.log(response);
            });
    }

    return <>
        <p>{t("tell_us_something_about_your_classroom")}</p>
        <Formik
            onSubmit={handleSubmit}
            validationSchema={OwnerAddClassroomFormValidationSchema}
            initialValues={
                {
                    idclassroom: 0,
                    userId: useSelector((state: ReduxState) => state.user.iduser),
                    location: '',
                    hardware: '',
                    hours_start: '09:00',
                    hours_end: '17:00',
                }
            }>
            {
                ({errors, isValid}) => (
                    <Form className={css.OwnerAddClassroom}>
                        <h2 ref={h2Ref}>
                            {t("tell_us_something_about_your_classroom")}
                        </h2>

                        <label htmlFor="hardware">{t("alias")}: </label>
                        <Field type="hardware" name="hardware" id="hardware"/>

                        <label htmlFor="location">{t('location')}: </label>
                        <Field type="text" name="location" id="location"/>

                        <p>_____________</p>

                        <label htmlFor="hours_start">{t('hours_start')}: </label>
                        <Field type="time" name="hours_start" id="hours_start" required/>

                        <label htmlFor="hours_end">{t('hours_end')}: </label>
                        <Field type="time" name="hours_end" id="hours_end" required/>

                        <br/>
                        <button
                            type="submit"
                            disabled={!isValid}  // need a flag to disable button
                            className="btn btn-dark"
                        >
                            {t('Add_this_classroom')}
                        </button>
                    </Form>
                )
            }
        </Formik>

    </>;

}


export default OwnerAddClassroom;