import appConstants from "../constants/constant";
import axios from 'axios';

export const getAllClassrooms = (idowner: number) => {
    const getAllClassroomsPromise = axios.get(
        appConstants.URL+'/classroom/showbyownerid/'+idowner
    );
    return {
        type: appConstants.GET_CLASSROOMS_BY_OWNER,
        payload: getAllClassroomsPromise,
    };
}

export const getPendingClassrooms = (idowner: number) => {
    const getPendingClassroomsPromise = axios.get(
        appConstants.URL+'/classroom/showpendingbyownerid/'+idowner
    );
    console.log(getPendingClassroomsPromise)
    return {
        type: appConstants.GET_PENDING_CLASSROOMS_BY_OWNER,
        payload: getPendingClassroomsPromise,
    };

}
