import appConstants from "../constants/constant";
import {AxiosResponse} from "axios";
import {UserModel} from "../models/user.model";

export const usersReducer = (
    state: UserModel[] | null = null,
    action: usersReducerAction
) => {

    switch (action.type) {
        case appConstants.GET_ALL_USERS:
            // console.log('reducer case: GET_ALL_USERS case');
            // console.log('reducer sent', (action.payload as AxiosResponse).data);
            return (action.payload as AxiosResponse).data;

        default:
            // console.log('reducer case: default case');
            return state;
    }
};

interface usersReducerAction {
    type: string;
    payload: AxiosResponse;
}