import {Component} from "react";
import {connect} from "react-redux";
import {UserModel} from "../models/user.model";
import {AxiosResponse} from "axios";
import { ReduxState} from "../constants/constant";
import {getAllUsers} from "../actions/users.action";

class ShowAllUsers extends Component<ShowAllUsersProps, any> {

    componentDidMount() {
        this.props.getAllUsers();
    }


    render() {

        return <>
            <div className='border border-dark w-75 m-3'>
                <table className={"table table-bordered border-primary"}>
                    <thead>
                    <tr>
                        <th>iduser</th>
                        <th>username</th>
                        <th>password</th>
                        <th>email</th>
                    </tr>
                    </thead>

                    <tbody>
                    {
                        this.props.userslist?.map(element => {
                            return (
                                <tr key={element.iduser}>
                                    <td>
                                        {element.iduser}
                                    </td>
                                    <td>{element.username}</td>
                                    <td>{element.password}</td>
                                    <td>{element.email}</td>

                                </tr>

                            )
                        })
                    }
                    </tbody>
                </table>
            </div>
        </>
    }
}


function mapStateToProps({userslist}: ReduxState) {
    return {userslist};
}

export default connect(mapStateToProps, {getAllUsers})(ShowAllUsers);

interface ShowAllUsersProps {
    userslist: UserModel[];
    getAllUsers: () => {
        type: string,
        payload: Promise<AxiosResponse>
    }
}
