import React, {FormEvent, SyntheticEvent, useEffect, useState} from "react";
import {Field, Form, Formik} from "formik";
import css from './TutorAddAvailability.module.scss'

import * as Yup from 'yup';
import axios from "axios";
import {AvailabilityModel} from "../models/Availability.model";
import constant from "../constants/constant";
import {useTranslation} from "react-i18next";


const TutorAddAvailabilityFormValidationSchema = Yup.object().shape({
    // username: Yup.string()
    //     .required('username is required')
});


const TutorAddAvailability = () => {
    const {t} = useTranslation();

    const data = window.localStorage.getItem('localStorageKey_user');
    const user = (data != 'undefined' && data) ? JSON.parse(data)
        :
        undefined;

    const handleFormSubmit = (formData: AvailabilityModel) => {
        axios({
            method: "put",
            url: constant.URL + '/availability/add',
            data: JSON.stringify(formData),
            headers: {"Content-Type": "application/json"},
        })
            .then(function (response) {
                console.log(response);
            })
            .catch(function (response) {
                console.log(response);
            });
    }

    const [formInitialValue, setFormInitialValue] = useState(
        {
            idavailability: 0,
            subject: "subject name",
            classroom_id: 0,
            hours_start: '09:00',
            hours_end: '17:00',

            user_id: user.iduser,
            availability_id: 0
        }
    );
    const [keyword, setKeyword] = useState('');
    const [pageCount, setPageCount] = useState(1);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemPerPage, setItemPerPage] = useState(5);
    const [classroomList, setClassroomList] = useState(
        [
            {
                idclassroom: 0,
                hours_start: "00:00:00",
                hours_end: "00:00:00",
                location: "location",
                hardware: ''
            }
        ]
    );

    useEffect(() => {
        console.log('useeffect classroom searchING axios data')
        axios.get(
            constant.URL + '/classroom/search?keyword=' + keyword +
            '&page=' + (currentPage - 1) +
            '&pageSize=' + itemPerPage
        )
            .then(res => {
                const data = res.data;
                // console.log('useeffect classroom  axios data:::', data)
                setClassroomList(data.content);
                setPageCount(data.totalPages);
            })
    }, [keyword, pageCount, itemPerPage, currentPage])


    function fillHandler(event: SyntheticEvent) {
        event.preventDefault();
        const target = event.target as HTMLInputElement;
        // console.log(target.value)
        // formInitialValue.classroom_id = +target.value;
        setFormInitialValue({
            idavailability: 0,
            subject: "subject name",
            classroom_id: +target.value,
            hours_start: '09:00',
            hours_end: '17:00',

            user_id: user.iduser,
            availability_id: 0
        })
    }

    return <>
        <div className="row">
            <div className="col-lg-8">
                <p>{t("heres_a_list_of_locations")}</p>

                <div className='border border-dark w-75 m-3'>
                    <table className={"table table-bordered border-primary"}>
                        <thead>
                        <tr>
                            <th>idclassroom</th>
                            <th>{t('hours_start')} ~ {t('hours_end')}</th>
                            <th>{t('location')}</th>
                            <th>{t('alias')}</th>
                        </tr>
                        </thead>
                        <tbody>
                        {
                            classroomList.map(element => {
                                return <tr key={element.idclassroom}>
                                    <td>{element.idclassroom}
                                        <button className="btn btn-outline-primary"
                                                onClick={fillHandler} value={element.idclassroom}>Fill Info to submit
                                            form
                                        </button>
                                    </td>
                                    <td>{element.hours_start}~{element.hours_end}</td>
                                    <td>{element.location}</td>
                                    <td>
                                        {element.hardware}
                                    </td>
                                </tr>
                            })
                        }
                        </tbody>
                    </table>
                    <div className="row align-items-center">
                        <div className="m-auto">
                            {t('currentPage')} / {t('totalPages')}: {currentPage} / {pageCount} &nbsp;&nbsp;&nbsp;

                            {currentPage >= 2 ? <button className="col"
                                                        onClick={() => setCurrentPage(1)}>1 </button> : null}

                            {currentPage >= 4 ? <button className="col">...</button> : null}

                            {currentPage >= 3 ? <button className="col"
                                                        onClick={() => setCurrentPage(currentPage - 1)}>{currentPage - 1}</button> : null}

                            <button className="btn btn-primary">{currentPage}</button>

                            {currentPage < pageCount - 1 ? <button className="col"
                                                                   onClick={() => setCurrentPage(currentPage + 1)}>{currentPage + 1}</button> : null}

                            {currentPage < pageCount - 2 ? <button className="col">...</button> : null}

                            {currentPage <= pageCount - 1 ? <button className="col"
                                                                   onClick={() => setCurrentPage(pageCount)}>{pageCount}</button> : null}

                        </div>
                    </div>

                    <form className="row"
                    >
                        <div className="form-group row">

                            <label htmlFor="staticEmail" className="col-sm-2 col-form-label">{t('Keyword')}</label>
                            <div className="col-sm-5">
                                <input type="text" className="form-control" id="keyword"
                                       placeholder="insert keyword here"
                                       value={keyword} onChange={(e) => setKeyword(e.target.value)}
                                >
                                </input>
                            </div>

                            <label htmlFor="inputPassword" className="col-sm-3 col-form-label">{t("ItemsPerPage")}</label>
                            <select className="col-sm-2 col-form-input"
                                    value={itemPerPage} onChange={(e) => setItemPerPage(+e.target.value)}
                            >
                                <option>1</option>
                                <option>2</option>
                                <option>3</option>
                                <option>5</option>
                                <option>10</option>
                            </select>
                        </div>
                    </form>

                </div>
            </div>

            <div className="col-lg-3">
                <Formik
                    onSubmit={handleFormSubmit}
                    validationSchema={TutorAddAvailabilityFormValidationSchema}
                    initialValues={formInitialValue}
                >
                    {
                        ({errors, isValid}) => (
                            <Form className={css.TutorAddAvailability}>
                                <h2> {t("which_class_you_want_to_teach")}</h2>

                                <label htmlFor="user_id">user_id: </label>
                                <Field type="text" name="user_id" id="user_id" disabled/>

                                <label htmlFor="classroom_id">{t('classroom')}_id: (use space here!!!???) </label>
                                <Field type="text" name="classroom_id" id="classroom_id"
                                       value={formInitialValue.classroom_id} />

                                <label htmlFor="subject">subject: </label>
                                <Field type="text" name="subject" id="location"/>

                                <p>_____________</p>

                                <label htmlFor="hours_start">{t("Tutor")} {t('s')} {t("hours_start")}: </label>
                                <Field type="time" name="hours_start" id="hours_start" required/>

                                <label htmlFor="hours_end">{t('Tutor')} {t('s')} {t('hours_end')}: </label>
                                <Field type="time" name="hours_end" id="hours_end" required/>

                                <br/>
                                <button
                                    type="submit"
                                    disabled={!isValid}  // need a flag to disable button
                                    className="btn btn-dark"
                                >
                                    {t("Add_this_classroom")}
                                </button>
                            </Form>
                        )
                    }
                </Formik>
            </div>
        </div>
    </>
        ;

}

export default TutorAddAvailability;