import {ProductModel} from "../models/product.model";
import appConstants from "../constants/constant";
import {AxiosResponse} from "axios";



export const productsReducer = (
    state: ProductModel[] | null=null,
    action: ProductsReducerAction
) => {

    switch (action.type) {
        case appConstants.GET_PRODUCTS:
            console.log('product reducer case: GET_PRODUCTS case');
            console.log('product reducer sent', (action.payload as AxiosResponse).data);
            console.log(action.payload);
            return (action.payload as AxiosResponse).data;

        default:
            // console.log('product reducer: default case')
            return state;
    }
};

interface ProductsReducerAction {
    type: string;
    // payload: ProductModel;
    payload: AxiosResponse;
}