import React, {Component, SyntheticEvent} from 'react';
import {ProductModel} from "../models/product.model";
import {appConstants, ReduxState} from "../constants/constant";
import {connect} from "react-redux";
import {getProducts} from "../actions/products.action";
import {AxiosResponse} from "axios";
import {Link, NavLink} from 'react-router-dom';

// import Product from "./product/Product"   // wtf

class Products extends Component<ProductsProps, any> {


    componentDidMount() {
        const returned = this.props.getProducts();
        console.log('this.props.getProducts:',returned)
        console.log('this.props.productList: ', this.props.products);


        this.props.getProducts();
    }

    editProductHandler = (event: SyntheticEvent) => {
        console.log(event.target);
        // return <Link to={{pathname: "/EditProduct"}}></Link>;
    }

    render() {
        return <table className={"table table-bordered border-primary"}>
            <thead>
            <tr>
                <th>name</th>
                <th>brand</th>
                <th>price</th>
                <th>stock</th>
            </tr>
            </thead>

            <tbody>
            {
                // this.props.products && this.props.products.map
                // making sure this exists, before map
                this.props.products?.map(element => {
                    return (
                        <tr key={element.id} onClick={this.editProductHandler}>
                            <td>
                            </td>
                            <td>{element.brand}</td>
                            <td>{element.price}</td>
                            <td>{element.stock}</td>
                            <td><img src={element.image} width="130px"/></td>

                        </tr>

                    )
                })
            }
            </tbody>
        </table>
    }
}

function mapStateToProps({products}: ReduxState) {
    return {products};
}

export default connect(mapStateToProps, {getProducts})(Products);

interface ProductsProps {
    products: ProductModel[];
    getProducts: () => {
        type: string,
        payload: Promise<AxiosResponse>    // payload is a
    }
}