import Modal from "react-modal";
import React from "react";


const customStyles = {
    content: {
        top: '50%',
        left: '50%',
        right: 'auto',
        bottom: 'auto',
        marginRight: '-50%',
        transform: 'translate(-50%, -50%)',
    },
};

Modal.setAppElement('#root');

const ShowOneUser = () => {


    const data = window.localStorage.getItem('localStorageKey_user');
    console.log(data)
    // data != 'undefined' && data && console.log('Dashboard: JSON.parse(data)', JSON.parse(data));
    const user = (data != 'undefined' && data) ? JSON.parse(data)
        :
        {username: 'if you see this , something is wrong', iduser: 0};


    return <>
        <h1>my personal info:</h1>

<h3>

    <br/>
    username: {user?.username}
    <br/>
    iduser: {user?.iduser}
    <br/>
    email: {user?.email}
    <br/>
    password: {user?.password}

</h3>
    </>
}


export default ShowOneUser;
