import React, {Suspense, SyntheticEvent, useEffect, useState} from "react";
import {NavLink, useHistory} from "react-router-dom";
import appConstants from "../constants/constant";
import {useDispatch} from "react-redux";
import {logout} from "../actions/auth.action";
import Modal from "react-modal";
import {Login} from "../login/Login";


import i18n from 'i18next'
import {initReactI18next, useTranslation} from 'react-i18next'
import {init} from "../constants/translation";


i18n.use(initReactI18next).init(init)

const customStyles = {
    content: {
        top: '50%',
        left: '50%',
        right: 'auto',
        bottom: 'auto',
        marginRight: '-50%',
        transform: 'translate(-50%, -50%)',
    },
};

Modal.setAppElement('#root');

const Header = () => {

    const {t} = useTranslation()

    const data = window.localStorage.getItem('localStorageKey_user');
    const user = (data != 'undefined' && data) ? JSON.parse(data) : undefined;


    const dispatch = useDispatch();
    const history = useHistory();
    const logoutHandler = (event: SyntheticEvent) => {
        event.preventDefault(); // pervent refresh of the page
        dispatch(
            logout(
                () => {
                    history.push(appConstants.dashboardRoute);
                },
                (msg: string) => {
                    console.log(msg);
                }
            )
        );
    };


    const [modalIsOpen, setIsOpen] = React.useState(false);

    function openModal() {
        setIsOpen(true);
    }

    function closeModal() {
        setIsOpen(false);
    }

    const [currentLan, setCurrentLan] = useState('en');
    useEffect(() => {

    }, [currentLan])

    const lanChangeHandler = (event: SyntheticEvent) => {
        event.preventDefault();
        const target = event.target as HTMLInputElement;
        i18n.changeLanguage(target.value);
        setCurrentLan(target.value)
    }

    return (
        <Suspense fallback="Loading">
            <nav className="navbar navbar-dark bg-dark navbar-expand-lg "
                 id='header_nav1010'>
                <a href="/" className="navbar-brand">{t('React_SPA')}</a>
                <ul className="nav navbar-nav">

                    <li className="nav-item">
                        <NavLink className="nav-link" to={appConstants.productsRoute}>
                            {t('Products')}
                        </NavLink>
                    </li>

                    <li className="nav-item">
                        <NavLink className="nav-link" to={appConstants.showAllUserRoute}>
                            {t('Show_all_users')}
                        </NavLink>
                    </li>

                    <li className="nav-item">
                        <NavLink className="nav-link" to={appConstants.dashboardRoute}>
                            {t('Dashboard')}
                        </NavLink>
                    </li>

                </ul>
                <ul className="nav navbar-nav ms-auto">
                    <li className="nav-item">
                        <select onChange={lanChangeHandler} value={currentLan}
                        >
                            <option value='en'>English</option>
                            <option value='cn'>中文</option>
                        </select>
                    </li>
                    {
                        !user ?
                            <>
                                <li className="nav-item">
                                    <button onClick={openModal}>
                                        {t('Log_in')}
                                    </button>
                                </li>
                                <li className="nav-item">
                                    <NavLink className="nav-link" to={appConstants.registerUserRoute}>
                                        {t('Register_as_User')}
                                    </NavLink>
                                </li>
                            </>
                            :
                            <>
                                <li className="nav-item">
                                    <NavLink className="nav-link" to={appConstants.personalInfoRoute}>
                                        {t('Hello')}, {user?.username} !!!!!!! {t('userid')}: {user?.iduser}
                                    </NavLink>
                                </li>
                                <li className="nav-item">
                                    <button className="" onClick={logoutHandler}>
                                        {t('Log_out')}
                                    </button>
                                </li>
                            </>

                    }
                </ul>
                <Modal
                    isOpen={modalIsOpen}
                    onRequestClose={closeModal}
                    style={customStyles}
                    contentLabel="Example Modal"
                >
                    <button onClick={closeModal}>{t('close')}</button>
                    !user ?
                    <Login></Login>
                    :
                    <div></div>
                </Modal>
            </nav>
        </Suspense>
    );
};


export default Header;